mapper.select:
SELECT sp.saving_product_id AS savingProductId, sp.kor_co_nm AS korCoNm, sp.fin_prdt_cd AS finPrdtCd, sp.fin_prdt_nm AS finPrdtNm, sp.max_limit AS maxLimit, sp.spcl_cnd AS benefit FROM saving_product sp WHERE 1 = 1
AND sp.kor_co_nm LIKE CONCAT('%', #{korCoNm}, '%')
AND CAST(REPLACE(sp.max_limit, ',', '') AS UNSIGNED) <= #{maxLimit}
